function QRCode(element,opts){if(typeof element==='string')element=document.getElementById(element);this.el=element;this.opts=opts||{};this.text=this.opts.text||'';this.draw()}
QRCode.prototype.draw=function(){var size=this.opts.width||128;var canvas=document.createElement('canvas');canvas.width=canvas.height=size;this.el.innerHTML='';this.el.appendChild(canvas);var ctx=canvas.getContext('2d');var hash=0;for(var i=0;i<this.text.length;i++){hash=(hash<<5)-hash+this.text.charCodeAt(i);hash&=hash}
for(var y=0;y<21;y++)for(var x=0;x<21;x++){var bit=((hash>>((x*y)%31))&1);ctx.fillStyle=bit?'#000':'#fff';ctx.fillRect(Math.floor(x*size/21),Math.floor(y*size/21),Math.ceil(size/21),Math.ceil(size/21))}}
QRCode.prototype.makeCode=function(t){this.text=t;this.draw()};
